select dish.id id, dish.name name, dish.price price, dish.image image, dish.description description, dish.status status, dish.update_time update_time, category.name as category_name from dish,category

        dish.category_id=category.id

            and name like concat('%',#{name},'%')


            and category_id = #{categoryId}


            and status = #{status}


order by update_time desc
